if post1_self_.valid()
        && post1_self_@ == pre_self_@.insert(k, v)
        && post2_self_.valid()
        && post2_self_@ == pre_self_@.insert(k, v) {

        K::cmp_properties();

        assert(post1_self_@ == post2_self_@);
        assert(post1_self_.m@ == post2_self_.m@);
        assert(post1_self_.m == post2_self_.m);

        assert(post1_self_.m@.dom() == post1_self_.keys@.to_set());
        assert(post2_self_.m@.dom() == post2_self_.keys@.to_set());
        assert(post1_self_.keys@.to_set() == post2_self_.keys@.to_set());

        assert(sorted(post1_self_.keys@));
        assert(sorted(post2_self_.keys@));
        assert(post1_self_.keys@.no_duplicates());
        assert(post2_self_.keys@.no_duplicates());

        lemma_sorted_no_dup_unique::<K>(post1_self_.keys@, post2_self_.keys@);

        assert(post1_self_.keys@ == post2_self_.keys@);
        assert(post1_self_.keys.v@ == post2_self_.keys.v@);
        assert(post1_self_.keys.v@ =~= post2_self_.keys.v@);

        assert(post1_self_.keys@.len() == post1_self_.vals.len());
        assert(post2_self_.keys@.len() == post2_self_.vals.len());
        assert(post1_self_.vals@.len() == post2_self_.vals@.len());

        assert forall |idx: int| 0 <= idx < post1_self_.vals@.len() implies
            post1_self_.vals@[idx] == post2_self_.vals@[idx] by {
            assert(post1_self_.m@[post1_self_.keys@.index(idx)] == post1_self_.vals@.index(idx));
            assert(post2_self_.m@[post2_self_.keys@.index(idx)] == post2_self_.vals@.index(idx));
            assert(post1_self_.keys@.index(idx) == post2_self_.keys@.index(idx));
        }
        assert(post1_self_.vals@ =~= post2_self_.vals@);

        assert(post1_self_.keys.v@ =~= post2_self_.keys.v@);
        axiom_vec_eq_view::<K>(post1_self_.keys.v, post2_self_.keys.v);
        assert(post1_self_.keys.v == post2_self_.keys.v);

        axiom_vec_eq_view::<ID>(post1_self_.vals, post2_self_.vals);
        assert(post1_self_.vals == post2_self_.vals);

        assert(post1_self_.keys == post2_self_.keys);
        assert(post1_self_ == post2_self_);
    }
